using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD SUMMARY ===");
        Console.WriteLine($"Build Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Collect all errors
        var errors = new List<(string Project, string Code, string File, int Line, int Col, string Message, string Subcategory)>();
        var warnings = new List<(string Project, string Code, string File, int Line, int Col, string Message)>();

        build.VisitAllChildren<Error>(e =>
        {
            string project = "";
            var node = e.Parent;
            while (node != null)
            {
                if (node is Project p)
                {
                    project = p.Name;
                    break;
                }
                node = node.Parent;
            }
            errors.Add((project, e.Code ?? "", e.File ?? "", e.LineNumber, e.ColumnNumber, e.Text ?? "", e.Subcategory ?? ""));
        });

        build.VisitAllChildren<Warning>(w =>
        {
            string project = "";
            var node = w.Parent;
            while (node != null)
            {
                if (node is Project p)
                {
                    project = p.Name;
                    break;
                }
                node = node.Parent;
            }
            warnings.Add((project, w.Code ?? "", w.File ?? "", w.LineNumber, w.ColumnNumber, w.Text ?? ""));
        });

        // Group errors by project
        Console.WriteLine($"=== ERRORS ({errors.Count} total) ===");
        var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
        foreach (var group in errorsByProject)
        {
            Console.WriteLine($"\n--- Project: {group.Key} ---");
            foreach (var e in group)
            {
                Console.WriteLine($"  [{e.Code}] {e.File}({e.Line},{e.Col}): {e.Message}");
            }
        }

        // Show warnings that might be relevant
        var relevantWarnings = warnings.Where(w => 
            w.Code?.StartsWith("CS") == true || 
            w.Code?.StartsWith("NU") == true ||
            w.Code?.StartsWith("MSB") == true
        ).ToList();

        if (relevantWarnings.Any())
        {
            Console.WriteLine($"\n=== RELEVANT WARNINGS ({relevantWarnings.Count}) ===");
            var warnsByProject = relevantWarnings.GroupBy(w => w.Project).OrderBy(g => g.Key);
            foreach (var group in warnsByProject)
            {
                Console.WriteLine($"\n--- Project: {group.Key} ---");
                foreach (var w in group)
                {
                    Console.WriteLine($"  [{w.Code}] {w.File}({w.Line},{w.Col}): {w.Message}");
                }
            }
        }

        // Analyze project dependency graph and build results
        Console.WriteLine("\n=== PROJECT BUILD RESULTS ===");
        build.VisitAllChildren<Project>(p =>
        {
            var projectErrors = new List<string>();
            p.VisitAllChildren<Error>(e => projectErrors.Add(e.Text));
            var status = projectErrors.Any() ? "FAILED" : "OK";
            if (status == "FAILED" || p.Name.Contains("FAILED"))
            {
                Console.WriteLine($"  {status}: {p.Name} ({p.ProjectFile}) - {projectErrors.Count} error(s)");
            }
        });

        // Look for dependency/reference issues
        Console.WriteLine("\n=== DEPENDENCY ANALYSIS ===");
        var projectsWithErrors = errors.Select(e => e.Project).Distinct().ToHashSet();

        // Check for MSB3202 (project file not found) or MSB4236 etc
        var refErrors = errors.Where(e => 
            e.Code == "MSB3202" || e.Code == "MSB4236" || e.Code == "MSB3245" ||
            e.Code == "CS0006" || e.Code == "CS0246" || e.Code == "CS0234" ||
            e.Message.Contains("could not be found") ||
            e.Message.Contains("does not exist") ||
            e.Message.Contains("ResolveAssemblyReference")
        ).ToList();

        if (refErrors.Any())
        {
            Console.WriteLine("Potential dependency/cascading errors:");
            foreach (var e in refErrors)
            {
                Console.WriteLine($"  [{e.Code}] in {e.Project}: {e.Message}");
            }
        }

        // Print all project nodes with their targets for context
        Console.WriteLine("\n=== ALL PROJECT ENTRIES ===");
        build.VisitAllChildren<Project>(p =>
        {
            Console.WriteLine($"  Project: {p.Name} | File: {p.ProjectFile} | Targets: {p.TargetFramework}");
        });
    }
}
